[CmdletBinding()]param()
$ErrorActionPreference='Stop';$root=(Resolve-Path (Join-Path $PSScriptRoot '..')).Path;$errors=[Collections.Generic.List[object]]::new();foreach($file in Get-ChildItem -LiteralPath $root -Recurse -Filter '*.ps1' -File|Where-Object{$_.FullName -notmatch '(?:\\node_modules\\|\\backups\\)'}){$tokens=$null;$parseErrors=$null;[System.Management.Automation.Language.Parser]::ParseFile($file.FullName,[ref]$tokens,[ref]$parseErrors)|Out-Null;foreach($e in $parseErrors){$errors.Add("$($file.FullName):$($e.Extent.StartLineNumber):$($e.Extent.StartColumnNumber) $($e.Message)")}};if($errors.Count){$errors|ForEach-Object{Write-Error $_};exit 1};Write-Host 'PowerShell syntax parse passed; this is not runtime verification.'
